// ------------------------------
// Funções auxiliares
// ------------------------------
function toBRL(n) {
  n = n !== null && n !== undefined ? parseFloat(n) : 0.0;
  return n.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
}

function toPct(n) {
  n = n !== null && n !== undefined ? parseFloat(n) : 0.0;
  return n.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 }) + '%';
}

function escapeHtml(str) {
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

// ------------------------------
// Processamento principal
// ------------------------------
const GATILHO_SLUG = "benchmark_cdi_pf";
let ids_destinatarios = [];
let items_notificacao = [];
const new_items = [];

// PRIMEIRA PASSAGEM: Separar dados de notificação dos IDs
for (const item of $input.all()) {
  const j = item.json;

  if ('id' in j && (typeof j.id === 'number' || typeof j.id === 'string') && !('detalhes' in j)) {
    try {
      ids_destinatarios.push(parseInt(j.id));
    } catch {
      ids_destinatarios.push(j.id);
    }
  } else if (GATILHO_SLUG in j || 'detalhes' in j) {
    items_notificacao.push(j);
  }
}

// Remove duplicados
ids_destinatarios = [...new Set(ids_destinatarios)];

// Fallback: usa ID 1 (Admin) se vazio
if (ids_destinatarios.length === 0) {
  console.log("AVISO: Array de destinatários vazio. Usando ID 1 (Admin) como fallback.");
  ids_destinatarios = [1];
}

// SEGUNDA PASSAGEM: Montar as notificações
if (items_notificacao.length === 0) {
  return [];
}

for (let idx_notificacao = 0; idx_notificacao < items_notificacao.length; idx_notificacao++) {
  const j_item = items_notificacao[idx_notificacao];
  const j = j_item[GATILHO_SLUG] ?? j_item;

  const detalhes_texto = escapeHtml(String(j.detalhes));
  const nome_alvo = j.nome_alvo;
  const id_alvo = j.id_alvo;
  const p50 = parseFloat(j.p50 ?? 0.0);
  const p90 = parseFloat(j.p90 ?? 0.0);
  const n_ratios = parseInt(j.n_ratios ?? 0);

  const is_mediana = String(j.detalhes).includes("Mediana");
  const valor_ratio = is_mediana ? p50 : p90;
  const label_ratio = is_mediana ? "Mediana (p50)" : "Percentil 90 (p90)";

  const limiar_baixa = j.limiar_ratio_baixa ?? null;
  const limiar_alta = j.limiar_ratio_alta ?? null;
  const limiar = limiar_baixa !== null ? limiar_baixa : limiar_alta;

  const descricao_html =
    `<p><strong>Detalhes da Avaliação:</strong></p>` +
    `<ol>` +
    `<li><strong>Mediana (p50):</strong> ${p50.toFixed(2)}</li>` +
    `<li><strong>Percentil 90 (p90):</strong> ${p90.toFixed(2)}</li>` +
    `<li><strong>Número de Clientes (Ratios Válidos):</strong> ${n_ratios}</li>` +
    `<p><em>Disparo de alerta quando o benchmark CDI (100%-120%) não é atendido pela rentabilidade (P50/P90) de clientes PF em 12 meses.</em></p>` +
    `</ol>`;

  for (const destinatario_id of ids_destinatarios) {
    new_items.push({
      json: {
        titulo: "⚠️ Alerta: Benchmark CDI - Cliente PF",
        descricao: descricao_html,
        destinatario: destinatario_id,
        tipo_notificacao: "Rentabilidade abaixo do benchmark",
      },
      pairedItem: { item: idx_notificacao },
    });
  }
}

return new_items;

